import React, { useState } from 'react';
import './App.css';

/* ─────────────────────────────────────────────
   SAMPLE GRAMMARS
───────────────────────────────────────────── */
const EXAMPLES = [
  { name: 'aⁿbⁿ',       grammar: 'S -> aSb | ab',                            input: 'aaabbb',   start: 'S' },
  { name: 'Simple AB',  grammar: 'S -> AB\nA -> aA | a\nB -> bB | b',        input: 'aab',      start: 'S' },
  { name: 'Arithmetic', grammar: 'E -> E+T | T\nT -> T*F | F\nF -> id',      input: 'id+id*id', start: 'E' },
  { name: 'Palindrome', grammar: 'S -> aSa | bSb | a | b',                   input: 'aba',      start: 'S' },
];

/* ─────────────────────────────────────────────
   PARSE TREE RENDERER
───────────────────────────────────────────── */
function looksLikeNT(symbol) {
  return /^[A-Z][A-Z0-9']*$/.test(symbol);
}

function TreeNode({ node, isRoot }) {
  if (!node) return null;

  const isEpsilon  = node.value === 'ε';
  const isTerminal = node.children.length === 0 && !looksLikeNT(node.value) && !isEpsilon;

  let nodeClass = 'tree-node-box tree-node-nt';
  if (isRoot)     nodeClass = 'tree-node-box tree-node-root';
  else if (isEpsilon)  nodeClass = 'tree-node-box tree-node-eps';
  else if (isTerminal) nodeClass = 'tree-node-box tree-node-t';

  const hasChildren = node.children && node.children.length > 0;

  return (
    <div className="tree-node-wrapper">
      <div className={nodeClass}>{node.value}</div>

      {hasChildren && (
        <>
          <div className="tree-connector-down" />
          <div className="tree-children-row">
            {node.children.map((child, i) => (
              <div key={i} className="tree-child-col">
                <div className="tree-child-line-down" />
                <TreeNode node={child} isRoot={false} />
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

function ParseTreeView({ tree }) {
  if (!tree) {
    return <p className="no-tree-msg">— parse tree unavailable —</p>;
  }
  return (
    <>
      <div className="tree-scroll-container">
        <div className="tree-center-wrap">
          <TreeNode node={tree} isRoot={true} />
        </div>
      </div>
      <div className="tree-legend">
        <div className="legend-item">
          <span className="legend-swatch legend-nt">NT</span>
          Non-terminal
        </div>
        <div className="legend-item">
          <span className="legend-swatch legend-t">t</span>
          Terminal
        </div>
        <div className="legend-item">
          <span className="legend-swatch legend-eps">ε</span>
          Epsilon
        </div>
      </div>
    </>
  );
}

/* ─────────────────────────────────────────────
   GRAMMAR DISPLAY
───────────────────────────────────────────── */
function GrammarDisplay({ rules }) {
  if (!rules || Object.keys(rules).length === 0) return null;
  return (
    <div className="glass-card grammar-display-card">
      <div className="card-header">
        <div className="card-title">
          <div className="card-title-dot dot-gray" />
          Parsed Rules
        </div>
      </div>
      <div className="grammar-rules-grid">
        {Object.entries(rules).map(([lhs, prods]) => (
          <div key={lhs} className="grammar-rule-row">
            <span className="rule-lhs">{lhs}</span>
            <span className="rule-arrow">→</span>
            <span className="rule-rhs">{prods.map(p => p.join('')).join('  |  ')}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ─────────────────────────────────────────────
   DERIVATION STEPS
───────────────────────────────────────────── */
function DerivationCard({ result, title, dotClass }) {
  const ok = result && result.success;
  return (
    <div className="glass-card derivation-card">
      <div className="card-header">
        <div className="card-title">
          <div className={`card-title-dot ${dotClass}`} />
          {title}
        </div>
        {ok
          ? <span className="status-badge badge-success">✓ {result.steps.length} steps</span>
          : <span className="status-badge badge-error">✗ Cannot derive</span>
        }
      </div>

      {ok ? (
        <ol className="step-list">
          {result.steps.map((step, i) => (
            <li key={i} className="step-item">
              <span className="step-num">{i}</span>
              {i > 0 && <span className="step-arrow-sym">⇒</span>}
              <span className="step-string">{step}</span>
            </li>
          ))}
        </ol>
      ) : (
        <p className="derivation-fail">
          {result ? result.message : 'No result available.'}
        </p>
      )}
    </div>
  );
}

/* ─────────────────────────────────────────────
   MAIN APP
───────────────────────────────────────────── */
function App() {
  const [grammar,     setGrammar]     = useState('S -> AB\nA -> aA | a\nB -> bB | b');
  const [inputString, setInputString] = useState('aab');
  const [startSymbol, setStartSymbol] = useState('S');
  const [loading,     setLoading]     = useState(false);
  const [error,       setError]       = useState('');
  const [result,      setResult]      = useState(null);

  function loadExample(ex) {
    setGrammar(ex.grammar);
    setInputString(ex.input);
    setStartSymbol(ex.start);
    setResult(null);
    setError('');
  }

  async function handleGenerate() {
    setError('');
    setResult(null);

    if (!grammar.trim())     { setError('Please enter grammar rules.'); return; }
    if (!startSymbol.trim()) { setError('Please enter a start symbol.'); return; }

    setLoading(true);
    try {
      const response = await fetch('/api/derive', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          grammar,
          input: inputString,
          startSymbol: startSymbol.trim(),
        }),
      });
      const data = await response.json();
      if (!response.ok) {
        setError(data.error || 'Server error. Is the backend running?');
        return;
      }
      setResult(data);
    } catch {
      setError('Cannot reach backend. Run:  cd backend && npm start');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="app-root">
      <div className="app-container">

        {/* ── Header ── */}
        <header className="app-header">
          <div className="header-eyebrow">
            <span className="header-eyebrow-dot" />
            Compiler Theory · CS Assignment
          </div>
          <h1 className="app-title">CFG Derivation &amp;<br />Parse Tree Generator</h1>
          <p className="app-subtitle">
            Visualise leftmost &amp; rightmost derivations for any context-free grammar
          </p>
        </header>

        {/* ── Examples ── */}
        <div className="examples-bar">
          <span className="examples-label">Try</span>
          {EXAMPLES.map(ex => (
            <button key={ex.name} className="example-chip" onClick={() => loadExample(ex)}>
              {ex.name}
            </button>
          ))}
        </div>

        {/* ── Input Card ── */}
        <div className="glass-card input-card">

          {/* Grammar Rules */}
          <div className="field-group">
            <div className="section-label">
              <div className="section-label-icon">G</div>
              Grammar Rules
            </div>
            <textarea
              className="grammar-textarea"
              value={grammar}
              onChange={e => setGrammar(e.target.value)}
              placeholder={'S -> AB\nA -> aA | a\nB -> bB | b'}
              spellCheck={false}
            />
            <p className="field-hint">
              Format: LHS → RHS alternatives separated by |&nbsp;&nbsp;·&nbsp;&nbsp;Uppercase = non-terminals&nbsp;&nbsp;·&nbsp;&nbsp;Lowercase = terminals
            </p>
          </div>

          {/* Start Symbol + String + Button */}
          <div className="field-group">
            <div className="section-label">
              <div className="section-label-icon">I</div>
              Input
            </div>
            <div className="fields-row">
              <div className="field-item">
                <label className="section-label" style={{ marginBottom: 0, fontSize: '10px' }}>Start Symbol</label>
                <input
                  className="text-input input-start"
                  value={startSymbol}
                  onChange={e => setStartSymbol(e.target.value)}
                  maxLength={5}
                  spellCheck={false}
                />
              </div>
              <div className="field-item">
                <label className="section-label" style={{ marginBottom: 0, fontSize: '10px' }}>Input String</label>
                <input
                  className="text-input input-string"
                  value={inputString}
                  onChange={e => setInputString(e.target.value)}
                  placeholder="e.g. aabb"
                  spellCheck={false}
                />
              </div>
              <button
                className="btn-generate"
                onClick={handleGenerate}
                disabled={loading}
              >
                <span className="btn-icon">▶</span>
                {loading ? 'Computing…' : 'Generate'}
              </button>
            </div>
          </div>
        </div>

        {/* ── Error ── */}
        {error && (
          <div className="error-box">
            <div className="error-icon">!</div>
            <p className="error-text">{error}</p>
          </div>
        )}

        {/* ── Loading ── */}
        {loading && (
          <div className="loading-box">
            <div className="loading-spinner" />
            Computing derivations…
          </div>
        )}

        {/* ── Results ── */}
        {result && (
          <div className="results-section">

            {/* Parsed grammar */}
            <GrammarDisplay rules={result.grammarRules} />

            {/* Leftmost derivation */}
            <DerivationCard
              result={result.leftmost}
              title="Leftmost Derivation"
              dotClass="dot-blue"
            />

            {/* Rightmost derivation */}
            <DerivationCard
              result={result.rightmost}
              title="Rightmost Derivation"
              dotClass="dot-violet"
            />

            {/* Parse tree */}
            <div className="glass-card parse-tree-card">
              <div className="card-header">
                <div className="card-title">
                  <div className="card-title-dot dot-cyan" />
                  Parse Tree
                </div>
                {result.parseTree
                  ? <span className="status-badge badge-success">✓ Generated</span>
                  : <span className="status-badge badge-error">✗ Not available</span>
                }
              </div>
              <ParseTreeView tree={result.parseTree} />
            </div>

          </div>
        )}

        <footer className="app-footer">
          CFG Derivation Generator · College Assignment
        </footer>
      </div>
    </div>
  );
}

export default App;
